class Solution {
public:
    vector<int> busiestServers(int k, vector<int>& arrival, vector<int>& load) {
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> available;
        for (int i = 0; i < k; i++) {
            available.push({0, i});
        }

        vector<int> requests(k, 0);
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> busy;

        for (int i = 0; i < arrival.size(); i++) {
            while (!busy.empty() && busy.top().first <= arrival[i]) {
                int time = busy.top().first;
                int server = busy.top().second % k;
                available.push({time, server});
                busy.pop();
            }

            int start = i % k;
            bool assigned = false;
            while (!available.empty()) {
                int server = available.top().second;
                available.pop();
                if (server >= start) {
                    requests[server]++;
                    busy.push({arrival[i] + load[i], server});
                    assigned = true;
                    break;
                } else if (server + k >= start) {
                    requests[server]++;
                    busy.push({arrival[i] + load[i], server + k});
                    assigned = true;
                    break;
                }
            }

            if (!assigned) {
                continue;
            }
        }

        int maxRequests = 0;
        for (int i = 0; i < k; i++) {
            maxRequests = max(maxRequests, requests[i]);
        }

        vector<int> result;
        for (int i = 0; i < k; i++) {
            if (requests[i] == maxRequests) {
                result.push_back(i);
            }
        }

        return result;
    }
};
